CREATE DEFINER=`u802160697_agrinew`@`127.0.0.1` PROCEDURE `sp_cleanup_old_data` (IN `p_days` INT)   BEGIN
    DECLARE v_cutoff_date DATETIME;
    DECLARE v_deleted_count INT DEFAULT 0;
    
    SET v_cutoff_date = DATE_SUB(NOW(), INTERVAL p_days DAY);
    
    START TRANSACTION;
    
    -- Delete from json_backup (cascade will handle related records)
    DELETE FROM json_backup WHERE backup_timestamp < v_cutoff_date;
    SET v_deleted_count = v_deleted_count + ROW_COUNT();
    
    -- Delete from node_logs
    DELETE FROM node_logs WHERE waktu < v_cutoff_date;
    SET v_deleted_count = v_deleted_count + ROW_COUNT();
    
    -- Delete from sensor_node_data
    DELETE FROM sensor_node_data WHERE received_at < v_cutoff_date;
    SET v_deleted_count = v_deleted_count + ROW_COUNT();
    
    -- Delete from sensor_weather_data
    DELETE FROM sensor_weather_data WHERE received_at < v_cutoff_date;
    SET v_deleted_count = v_deleted_count + ROW_COUNT();
    
    -- Delete from getdata_logs
    DELETE FROM getdata_logs WHERE waktu_mulai < v_cutoff_date;
    SET v_deleted_count = v_deleted_count + ROW_COUNT();
    
    COMMIT;
    
    SELECT 
        v_deleted_count as total_deleted,
        v_cutoff_date as cutoff_date,
        NOW() as cleanup_time;
END$$

CREATE DEFINER=`u802160697_agrinew`@`127.0.0.1` PROCEDURE `sp_get_session_details` (IN `p_sesi_id` INT)   BEGIN
    -- Get main session info
    SELECT * FROM getdata_logs WHERE sesi_id_getdata = p_sesi_id;
    
    -- Get weather data
    SELECT * FROM sensor_weather_data WHERE sesi_id_getdata = p_sesi_id;
    
    -- Get node data
    SELECT * FROM sensor_node_data WHERE sesi_id_getdata = p_sesi_id ORDER BY node_id;
    
    -- Get node logs
    SELECT * FROM node_logs WHERE sesi_id = p_sesi_id ORDER BY waktu;
    
    -- Get JSON backup
    SELECT 
        id, 
        sesi_id_getdata, 
        data_size_kb, 
        total_records, 
        node_completeness, 
        backup_timestamp 
    FROM json_backup 
    WHERE sesi_id_getdata = p_sesi_id;
END$$

CREATE DEFINER=`u802160697_agrinew`@`127.0.0.1` PROCEDURE `sp_get_statistics` ()   BEGIN
    -- Overall statistics
    SELECT 
        'Overview' as category,
        COUNT(DISTINCT sesi_id_getdata) as total_sessions,
        SUM(total_records) as total_records,
        AVG(data_size_kb) as avg_size_kb,
        MIN(backup_timestamp) as first_data,
        MAX(backup_timestamp) as latest_data
    FROM json_backup;
    
    -- Records by table
    SELECT 'getdata_logs' as table_name, COUNT(*) as record_count FROM getdata_logs
    UNION ALL
    SELECT 'sensor_weather_data', COUNT(*) FROM sensor_weather_data
    UNION ALL
    SELECT 'sensor_node_data', COUNT(*) FROM sensor_node_data
    UNION ALL
    SELECT 'node_logs', COUNT(*) FROM node_logs
    UNION ALL
    SELECT 'json_backup', COUNT(*) FROM json_backup;
    
    -- Node activity
    SELECT * FROM v_node_activity;
    
    -- Daily stats (last 30 days)
    SELECT * FROM v_daily_stats LIMIT 30;
END$$

DELIMITER ;

